import{_ as d}from"./chunks/Delete24Regular.BPl04VSh.js";import{_ as a}from"./chunks/Add16Regular.kVgxK51v.js";import{_ as r,c as o,o as i,a3 as c}from"./chunks/framework.CTM16EAR.js";const t="data:image/svg+xml,%3csvg%20xmlns='http://www.w3.org/2000/svg'%20xmlns:xlink='http://www.w3.org/1999/xlink'%20viewBox='0%200%2020%2020'%3e%3cg%20fill='none'%3e%3cpath%20d='M14.5%2011h-1a.5.5%200%200%200%200%201h1a.5.5%200%200%200%200-1zm-10-8A1.5%201.5%200%200%200%203%204.5v10A2.5%202.5%200%200%200%205.5%2017h10a1.5%201.5%200%200%200%201.5-1.5v-9a1.5%201.5%200%200%200-1-1.415V4.5A1.5%201.5%200%200%200%2014.5%203h-10zM4%2014.5V5.915c.156.055.325.085.5.085h11a.5.5%200%200%201%20.5.5v9a.5.5%200%200%201-.5.5h-10A1.5%201.5%200%200%201%204%2014.5zM4.5%204h10a.5.5%200%200%201%20.5.5V5H4.5a.5.5%200%200%201%200-1z'%20fill='currentColor'%3e%3c/path%3e%3c/g%3e%3c/svg%3e",l="data:image/svg+xml,%3csvg%20xmlns='http://www.w3.org/2000/svg'%20xmlns:xlink='http://www.w3.org/1999/xlink'%20viewBox='0%200%2020%2020'%3e%3cg%20fill='none'%3e%3cpath%20d='M10%202a8%208%200%201%201%200%2016a8%208%200%200%201%200-16zm0%201a7%207%200%201%200%200%2014a7%207%200%200%200%200-14zm0%2010.5a.75.75%200%201%201%200%201.5a.75.75%200%200%201%200-1.5zm0-8a2.5%202.5%200%200%201%201.651%204.377l-.154.125l-.219.163l-.087.072a1.968%201.968%200%200%200-.156.149c-.339.36-.535.856-.535%201.614a.5.5%200%200%201-1%200c0-1.012.293-1.752.805-2.298a3.11%203.11%200%200%201%20.356-.323l.247-.185l.118-.1A1.5%201.5%200%201%200%208.5%208a.5.5%200%200%201-1%20.001A2.5%202.5%200%200%201%2010%205.5z'%20fill='currentColor'%3e%3c/path%3e%3c/g%3e%3c/svg%3e",k=JSON.parse('{"title":"收支账本使用方法","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference/ledger.md","filePath":"guide/reference/ledger.md","lastUpdated":1784796507000}'),n={name:"guide/reference/ledger.md"};function s(g,e,h,b,m,u){return i(),o("div",null,e[0]||(e[0]=[c('<h1 id="收支账本使用方法" tabindex="-1">收支账本使用方法 <a class="header-anchor" href="#收支账本使用方法" aria-label="Permalink to &quot;收支账本使用方法&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>本软件 <strong>不是</strong>专业记账工具：没有余额、对账、多账套。目标是在计划表标题里<strong>顺手记下几笔</strong>，方便回看与统计——这就是内置的<strong>收支账本</strong>。</p></div><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><ul><li>我想在标题里记一笔：见 <a href="#在标题里记账">在标题里记账</a></li><li>我想看某一天某条的明细：见 <a href="#查看单条明细">查看单条明细</a></li><li>我想看一段时间的汇总：见 <a href="#收支统计">收支统计</a></li><li>我想改 / 删 / 追加：见 <a href="#在统计里改删追加">在统计里改删追加</a></li><li>我想用标签当分类：见 <a href="#分类标签">分类标签</a></li><li>我想确认边界：见 <a href="#限制与说明">限制与说明</a></li></ul><h2 id="常用按钮" tabindex="-1">常用按钮 <a class="header-anchor" href="#常用按钮" aria-label="Permalink to &quot;常用按钮&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">按钮图标</th><th style="text-align:left;">功能说明</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+t+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 255, 255);border-radius:6px;"></td><td style="text-align:left;">计划表顶栏：打开<strong>收支统计</strong>；待办 / 预约行上：打开该条已录入明细</td></tr><tr><td style="text-align:center;"><img src="'+l+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 252, 252);border-radius:6px;"></td><td style="text-align:left;">统计弹窗内：展开 / 收起书写帮助</td></tr><tr><td style="text-align:center;"><img src="'+d+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 254, 254);border-radius:6px;"></td><td style="text-align:left;">删除一笔（软删；标题汇总会尽量同步）</td></tr><tr><td style="text-align:center;"><img src="'+a+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 255, 255);border-radius:6px;"></td><td style="text-align:left;">统计明细最下行：追加一笔（不经过标题语法）</td></tr></tbody></table><h2 id="在标题里记账" tabindex="-1">在标题里记账 <a class="header-anchor" href="#在标题里记账" aria-label="Permalink to &quot;在标题里记账&quot;">​</a></h2><p>适合在<strong>日视图</strong>编辑待办或预约的标题时顺手记。</p><ol><li>编辑标题，写入金额段（见下表语法）。</li><li>用结尾符表达「这一段要入账」：<code>￥</code> / <code>¥</code> / <code>$</code> / <code>%</code>（手机键盘常用 <code>%</code>）。</li><li><strong>退出编辑</strong>（失焦或回车）后才会解析入账；仅输入结尾符当下不会单独入账。</li><li>入账成功后，标题会变成「日记正文 + 汇总括号」，例如 <code>买菜 西瓜（-55）</code>。</li></ol><h3 id="书写语法" tabindex="-1">书写语法 <a class="header-anchor" href="#书写语法" aria-label="Permalink to &quot;书写语法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>写法</th><th>含义</th></tr></thead><tbody><tr><td><code> -30</code> / <code> +500</code>（空格后）或行首 <code>-30</code> / <code>+500</code></td><td>开始一笔；默认支出，<code>+</code> 为收入</td></tr><tr><td><code>￥</code> <code>¥</code> <code>$</code> <code>%</code>（及全角 <code>＄</code> <code>％</code>）</td><td><strong>记账段结束</strong>；没有结尾符则<strong>整段不入账</strong></td></tr><tr><td><code>;</code> / <code>；</code> 或段内再次出现 <code> -/+金额</code></td><td>同段多笔分隔</td></tr><tr><td><code>#分类名</code></td><td>写在记账段内时作为<strong>收支分类</strong>（不是活动标签，见 <a href="#分类标签">分类标签</a>）</td></tr></tbody></table><p>金额为正数，最多两位小数。金额后须接空格、<code>#</code>、<code>;</code>、结尾符或段尾，避免把 <code>-3度</code> 误当成记账。</p><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>保存前（编辑框）</th><th>保存后标题（示意）</th></tr></thead><tbody><tr><td><code>买菜 -30 西瓜 -25#菜市 喝的￥</code></td><td><code>买菜 西瓜 喝的（-55）</code></td></tr><tr><td><code>奖金 +5000; 午饭 -30%</code></td><td><code>奖金 午饭（-30 +5000）</code></td></tr><tr><td><code>-10 早餐￥</code></td><td><code>早餐（-10）</code></td></tr><tr><td><code>开会 -30买菜</code>（无结尾符）</td><td><strong>不入账</strong>，原文保留</td></tr><tr><td><code>今天 -3度出门</code>（无结尾符）</td><td><strong>不入账</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>汇总括号里的数字是整数、且只显示非零项。再次编辑时会先剥掉旧括号，再按当前标题解析。</p></div><h2 id="查看单条明细" tabindex="-1">查看单条明细 <a class="header-anchor" href="#查看单条明细" aria-label="Permalink to &quot;查看单条明细&quot;">​</a></h2><ul><li>当某条待办或预约已有未删除的收支时，行上会出现 <img src="'+t+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;">。</li><li>点击可查看该条关联的笔数、分类、备注与金额；可删除单笔。</li><li>删除后会尽量从标题正文去掉对应备注，并重写汇总括号；若你已大幅改过标题对不上，则可能只更新括号。</li></ul><h2 id="收支统计" tabindex="-1">收支统计 <a class="header-anchor" href="#收支统计" aria-label="Permalink to &quot;收支统计&quot;">​</a></h2><ol><li>在计划表顶栏点击 <img src="'+t+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 255, 255);border-radius:6px;">（标题「收支统计」）。</li><li>弹窗内可见：笔数、支出、收入、结余；支出分类饼图；收支趋势；明细表。</li><li>明细表头可切换排序： <ul><li>日期（时序）</li><li>分类</li><li>金额（从多到少）</li></ul></li><li>在<strong>日 / 周</strong>视图下，可点击「收支趋势」中的日期，切换本软件当前日期（便于对照某一天）。</li><li>需要语法提示时，点明细旁的 <img src="'+l+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(255, 255, 255);border-radius:6px;">。</li></ol><h2 id="在统计里改删追加" tabindex="-1">在统计里改删追加 <a class="header-anchor" href="#在统计里改删追加" aria-label="Permalink to &quot;在统计里改删追加&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>做法</th></tr></thead><tbody><tr><td><strong>改</strong></td><td>在明细行直接改分类、备注、金额；失焦或回车生效。来自标题的行改金额后，对应标题汇总括号会更新。</td></tr><tr><td><strong>删</strong></td><td>行首 <img src="'+d+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;"></td></tr><tr><td><strong>追加</strong></td><td>最下行点 <img src="'+a+'" width="20" style="display:inline-block;vertical-align:middle;margin:0;background:rgb(193, 226, 255);border-radius:6px;">，填金额后失焦或回车；分类可选、备注可选。追加日期与 <strong>本软件当前选中日期</strong>一致。</td></tr></tbody></table><h2 id="分类标签" tabindex="-1">分类标签 <a class="header-anchor" href="#分类标签" aria-label="Permalink to &quot;分类标签&quot;">​</a></h2><ul><li>在<strong>记账段内</strong>输入 <code>#</code> 并选择标签 → 写入该笔的分类，<strong>不会</strong>变成活动上的标签。</li><li>在<strong>结尾符之后</strong>或标题其它位置输入 <code>#</code> → 仍是普通 <a href="./tag.html">活动标签</a>。</li><li>统计弹窗里点分类列，也可为该笔选择 / 新建分类标签。</li></ul><p>示例：</p><ul><li><code>买菜 -30#菜</code> → 选「菜市」→ 分类归到菜市</li><li><code>买菜 -30￥ #紧急</code> → <code>#紧急</code> 在结尾符后 → 活动标签</li></ul><h2 id="限制与说明" tabindex="-1">限制与说明 <a class="header-anchor" href="#限制与说明" aria-label="Permalink to &quot;限制与说明&quot;">​</a></h2><ul><li><strong>必须有结尾符</strong>才入账；没有 <code>￥</code> / <code>$</code> / <code>%</code> 等时，全文当普通标题。</li><li>同一标题多次保存：有新记账段则<strong>追加</strong>新行；没有新段时<strong>不删</strong>旧行，仍会重写汇总括号。</li><li>登录账号后，收支可随云同步保存；清本地后重新登录，已同步数据应仍可见（依赖网络与账号状态，见 <a href="./../intro/account-and-data.html">账号与数据</a>）。</li><li>不做余额、对账、报表导出；复杂账本请用外部工具。</li></ul>',27)]))}const y=r(n,[["render",s]]);export{k as __pageData,y as default};
